#!/usr/bin/env python3\n\"\"\"Main training script for Recursive Logic Engine.\"\"\"\n\nimport argparse\nimport logging\nfrom pathlib import Path\n\nimport torch\nimport torch.nn as nn\nfrom torch.optim import AdamW\nfrom transformers import GPT2LMHeadModel, GPT2Tokenizer\n\nfrom src.utils.config import load_all_configs, get_config_value\nfrom src.utils.logging import setup_logging, log_hyperparams\nfrom src.utils.wandb_integration import create_wandb_tracker\nfrom src.data.loader import create_dataloaders, split_dataset, load_jsonl\nfrom src.training.trainer import Trainer\n\n\ndef create_dummy_dataset(num_samples: int = 100) -> list:\n    \"\"\"\n    Create dummy dataset for demonstration.\n    \n    In production, replace with actual datasets (GSM8K, MATH, etc.)\n    \"\"\"\n    dataset = []\n    for i in range(num_samples):\n        dataset.append({\n            \"input\": f\"Logic puzzle {i}: If A > B and B > C, what is the relationship between A and C?\",\n            \"output\": f\"A > C by transitivity.\",\n            \"thinking\": \"I need to apply the transitive property of inequalities.\",\n        })\n    return dataset\n\n\ndef main():\n    # Parse arguments\n    parser = argparse.ArgumentParser(description=\"Train Recursive Logic Engine\")\n    parser.add_argument(\"--config\", type=str, default=\"config/train.yaml\")\n    parser.add_argument(\"--output-dir\", type=str, default=\"outputs\")\n    parser.add_argument(\"--device\", type=str, default=\"cuda\" if torch.cuda.is_available() else \"cpu\")\n    parser.add_argument(\"--seed\", type=int, default=42)\n    args = parser.parse_args()\n    \n    # Set seeds\n    torch.manual_seed(args.seed)\n    \n    # Load config\n    config = load_all_configs(args.config)\n    \n    # Setup logging\n    logger = setup_logging(\n        log_file=str(Path(args.output_dir) / \"training.log\"),\n        level=config.get(\"logging\", {}).get(\"level\", \"INFO\"),\n    )\n    \n    log_hyperparams(logger, config)\n    \n    # Setup W&B\n    wandb_tracker = create_wandb_tracker(config)\n    \n    # Create output directory\n    Path(args.output_dir).mkdir(parents=True, exist_ok=True)\n    \n    logger.info(f\"Using device: {args.device}\")\n    \n    # Load model and tokenizer\n    logger.info(\"Loading model and tokenizer...\")\n    model_name = config[\"model\"][\"name\"]\n    model = GPT2LMHeadModel.from_pretrained(model_name)\n    tokenizer = GPT2Tokenizer.from_pretrained(model_name)\n    tokenizer.pad_token = tokenizer.eos_token\n    \n    # Create reference model (frozen copy)\n    reference_model = GPT2LMHeadModel.from_pretrained(model_name)\n    reference_model.eval()\n    for param in reference_model.parameters():\n        param.requires_grad = False\n    \n    # Load or create dataset\n    logger.info(\"Loading dataset...\")\n    try:\n        # Try to load from file\n        dataset = load_jsonl(\"data/logic_puzzles.jsonl\")\n        logger.info(f\"Loaded {len(dataset)} examples from file\")\n    except FileNotFoundError:\n        # Create dummy dataset for demonstration\n        logger.warning(\"Dataset file not found, creating dummy dataset\")\n        dataset = create_dummy_dataset(\n            config[\"data\"][\"total_samples\"]\n        )\n    \n    # Split dataset\n    train_data, val_data, test_data = split_dataset(\n        dataset,\n        train_ratio=0.8,\n        val_ratio=0.1,\n        seed=args.seed,\n    )\n    \n    # Create dataloaders\n    train_loader, val_loader, test_loader = create_dataloaders(\n        train_data=train_data,\n        val_data=val_data,\n        test_data=test_data,\n        tokenizer=tokenizer,\n        batch_size=config[\"training\"][\"batch_size\"],\n        dataset_type=\"logic\",\n    )\n    \n    logger.info(f\"Train: {len(train_data)}, Val: {len(val_data)}, Test: {len(test_data)}\")\n    \n    # Setup optimizer\n    optimizer = AdamW(\n        model.parameters(),\n        lr=config[\"training\"][\"learning_rate\"],\n        weight_decay=config[\"training\"].get(\"weight_decay\", 0.01),\n    )\n    \n    # Create trainer\n    trainer = Trainer(\n        model=model,\n        reference_model=reference_model,\n        train_loader=train_loader,\n        val_loader=val_loader,\n        optimizer=optimizer,\n        config=config,\n        device=args.device,\n        wandb_tracker=wandb_tracker,\n    )\n    \n    # Train\n    trainer.train(\n        num_epochs=config[\"training\"][\"num_epochs\"],\n        eval_every=config[\"training\"][\"eval_every\"],\n        save_every=config[\"training\"][\"save_every\"],\n        checkpoint_dir=str(Path(args.output_dir) / \"checkpoints\"),\n    )\n    \n    logger.info(\"Training complete!\")\n    logger.info(f\"Best model saved to {args.output_dir}/checkpoints/best_model.pt\")\n\n\nif __name__ == \"__main__\":\n    main()\n